const body = $json.body ?? $json;
const expectedSecret = $env.NOMADABE_CHAT_WEBHOOK_SECRET;
const providedSecret = body.secret ?? $headers['x-nomadabe-secret'];

if (expectedSecret && providedSecret !== expectedSecret) {
  throw new Error('Unauthorized Nomadabe AI chat request');
}

const rawMessages = Array.isArray(body.messages) ? body.messages : [];
const messages = rawMessages
  .slice(-10)
  .map((message) => ({
    role: message.role === 'assistant' ? 'assistant' : 'user',
    content: String(message.content ?? '').trim().slice(0, 1600),
  }))
  .filter((message) => message.content);

if (!messages.length || messages[messages.length - 1].role !== 'user') {
  throw new Error('At least one latest user message is required');
}

const systemPrompt = String(body.systemPrompt ?? '').trim();
const model = String(body.model ?? $env.DEEPSEEK_MODEL ?? 'deepseek-v4-flash').trim();

return [
  {
    json: {
      source: String(body.source ?? 'nomadabe-web'),
      model,
      messages: [
        {
          role: 'system',
          content: systemPrompt || 'Чи Nomadabe Travel-ийн AI туслах. Монгол хэлээр аяллын зөвлөгөө өг.',
        },
        ...messages,
      ],
    },
  },
];

const reply = String(
  $json.choices?.[0]?.message?.content ??
  $json.data?.reply ??
  $json.reply ??
  $json.output ??
  ''
).trim();

if (!reply) {
  throw new Error('DeepSeek returned an empty reply');
}

return [
  {
    json: {
      ok: true,
      data: {
        reply,
      },
    },
  },
];
